import json
from autogen import AssistantAgent, UserProxyAgent, register_function

llm_config = {"config_list": [{"model": "gpt-4o-mini", "api_key": "sk-..."}]}

assistant = AssistantAgent("assistant", llm_config=llm_config)
user_proxy = UserProxyAgent("user_proxy", human_input_mode="NEVER",
    code_execution_config=False,
    is_termination_msg=lambda m: "TERMINATE" in (m.get("content") or ""))

def search_products(query: str, max_results: int = 5) -> str:
    """Search a product catalogue and return matching items as JSON."""
    # Simulated results
    results = [
        {"name": f"Product {i}", "price": 9.99 * i, "in_stock": i % 2 == 0}
        for i in range(1, max_results + 1)
    ]
    return json.dumps({"query": query, "results": results})

register_function(search_products, caller=assistant, executor=user_proxy,
    name="search_products",
    description="Search the product catalogue. Returns JSON with matching items.")

user_proxy.initiate_chat(assistant,
    message="Find the top 3 products matching 'wireless headphones'.")

import json

def safe_divide(numerator: float, denominator: float) -> str:
    """Divide numerator by denominator. Returns the result or an error message."""
    if denominator == 0:
        return json.dumps({"error": "Division by zero is not allowed."})
    return json.dumps({"result": numerator / denominator})

# If the LLM calls safe_divide(10, 0), it receives:
# {"error": "Division by zero is not allowed."}
# and can explain this to the user or ask for a different denominator.
